  "options": [
    {
      "text": "ऑब्जेक्ट्स को मैन्युअल रूप से ले जाएँ"
    },
    {
      "text": "स्टोरेज क्लासेज़ के बीच ऑब्जेक्ट्स को स्वचालित रूप से ट्रांज़िशन करें"
    },
    {
      "text": "पुराने ऑब्जेक्ट्स को कभी न हटाएँ"
    },
    {
      "text": "सब कुछ स्टैंडर्ड क्लास में संग्रहीत करें"
    }
  ],
  "questionProse": [
    "S3 लाइफ़साइकल प्रबंधन क्या सक्षम करता है?"
  ],
  "questionCode": [],
  "explanationProse": [
    "लाइफ़साइकल प्रबंधन:\n    - स्टोरेज क्लासेज़ के बीच ऑब्जेक्ट्स को स्वचालित रूप से ट्रांज़िशन करें\n    - कम उपयोग वाले डेटा को सस्ते स्टोरेज में ले जाएँ\n    - ऑब्जेक्ट समाप्ति के नियम सेट करें\n    - स्टोरेज लागत को अनुकूलित करें\n    - मैन्युअल प्रबंधन ओवरहेड को घटाएँ\n\n    [S3 Lifecycle Rules](https://docs.aws.amazon.com/AmazonS3/latest/userguide/lifecycle-configuration-examples.html)"
  ],
